def gen(rng, size):
    words = set()
    for _ in range(size // 10):
        base = ''.join(rng.choice('abcde') for _ in range(rng.randint(1, 5)))
        for k in range(1, len(base) + 1):
            if rng.random() < 0.8:
                words.add(base[:k])
    for _ in range(size // 10):
        words.add(''.join(rng.choice('abcde') for _ in range(rng.randint(1, 6))))
    return [list(words)]

