class Solution:
    def longestWord(self, words):
        wset = set(words)
        best = ''
        for w in words:
            ok = all(w[:k] in wset for k in range(1, len(w) + 1))
            if ok:
                if len(w) > len(best) or (len(w) == len(best) and w < best):
                    best = w
        return best

