var longestWord = function(words) {
    const wset = new Set(words);
    const sorted = words.slice().sort();
    let best = '';
    for (const w of sorted) {
        let ok = true;
        for (let k = 1; k < w.length; k++) {
            if (!wset.has(w.slice(0, k))) { ok = false; break; }
        }
        if (ok && w.length > best.length) best = w;
    }
    return best;
};
